const results = [];

for (const item of $input.all()) {
  const car = item.json.brand + ' ' + item.json.model;
  const averageYear = Math.round((item.json.year_min + item.json.year_max) / 2);
  const carSearchValue = car + ' ' + averageYear || 'Ford';
  const urlString = encodeURIComponent(carSearchValue);

  item.json.carSearchValue = carSearchValue;
  item.json.urls = [
    `https://www.facebook.com/marketplace/cuenca/search/?daysSinceListed=7&sortBy=creation_time_descend&query=${urlString}&exact=false&locale=es_LA`,
    `https://www.facebook.com/marketplace/cuenca/search/?category_id=546583916084032&sortBy=creation_time_descend&query=${urlString}&referral_ui_component=category_menu_item`
  ];

  results.push({ json: item.json });
}

return results;

const searchValue = $input.first().json.body.searchValue
const result = encodeURIComponent(searchValue).toLowerCase()

return [{
  json: {
    urls: [
      `https://www.facebook.com/marketplace/cuenca/search/?daysSinceListed=7&sortBy=creation_time_descend&query=${result}&exact=false&locale=es_LA`,
      `https://www.facebook.com/marketplace/cuenca/search/?category_id=546583916084032&sortBy=creation_time_descend&query=${result}&referral_ui_component=category_menu_item`
    ]
  }
}];

const allPrices = [];

function extractYear(titleText, descText) {
  const text = titleText + " " + (descText ?? "");
  const yearMatch = text.match(/\b(19|20)\d{2}\b/);
  return yearMatch ? yearMatch[0] : null;
}

function getDerivedRegion(loc) {
  if (!loc || typeof loc !== 'string') return null;
  const lower = loc.toLowerCase();
  const COAST = ['guayaquil','manta','esmeraldas','machala','santo domingo','portoviejo','babahoyo','quevedo','milagro','daule','salinas','samborondón','durán','manabí','santa elena'];
  const SIERRA = ['quito','cuenca','ambato','riobamba','loja','ibarra','tulcán','latacunga','guaranda','azogues','cañar','chordeleg'];
  if (COAST.some(c => lower.includes(c))) return 'costa';
  if (SIERRA.some(c => lower.includes(c))) return 'sierra';
  return null;
}

// ========== EXTRAER IMÁGENES DEL LISTING ==========
function extractImageUrls(car) {
  const urls = [];

  const extraPhotos =
    car.listing_photos ?? car.media ?? car.photos ?? car.listing_images ?? [];

  for (const photo of extraPhotos) {
    const uri =
      photo?.listing_image?.uri ??
      photo?.image?.uri ??
      photo?.uri ??
      (typeof photo === "string" ? photo : null);

    const primaryUri = car.primary_listing_photo?.listing_image?.uri;
    if (uri && uri !== primaryUri && !urls.includes(uri)) {
      urls.push(uri);
    }
  }

  return urls;
}

// ========== FUNCIÓN PARA LIMPIAR CARACTERÍSTICAS ==========
function cleanCharacteristics(characteristics) {
  // Si es null o undefined, retornar null
  if (!characteristics) return null;

  // Si es un string vacío, retornar null
  if (typeof characteristics === "string" && characteristics.trim() === "") {
    return null;
  }

  // Si es un array
  if (Array.isArray(characteristics)) {
    // Si está vacío, retornar null
    if (characteristics.length === 0) return null;

    // Filtrar elementos vacíos o inválidos
    const filtered = characteristics.filter((item) => {
      if (typeof item === "string") return item.trim() !== "";
      if (typeof item === "object" && item !== null) return true;
      return false;
    });

    // Si después de filtrar está vacío, retornar null
    return filtered.length > 0 ? filtered : null;
  }

  // Si es un objeto
  if (typeof characteristics === "object") {
    // Verificar si tiene propiedades válidas
    const keys = Object.keys(characteristics);
    if (keys.length === 0) return null;

    // Verificar si todas las propiedades están vacías
    const hasValidData = keys.some((key) => {
      const value = characteristics[key];
      if (typeof value === "string") return value.trim() !== "";
      if (Array.isArray(value)) return value.length > 0;
      return value !== null && value !== undefined;
    });

    return hasValidData ? characteristics : null;
  }

  // Si es un string válido, retornarlo
  if (typeof characteristics === "string") {
    return characteristics;
  }

  return null;
}

// ========== EXTRAER DATOS DE OPENAI ==========
// ========== EXTRAER DATOS DE OPENAI ==========
let openAiDataArray = [];

for (const filterItem of $("Filter").all()) {
  const data = filterItem.json;
  if (data?.id) {
    openAiDataArray.push(data);
  }
}

// ========== FILTRAR ITEMS EXCLUIDOS ==========
openAiDataArray = openAiDataArray.filter((data) => !data.excluded);

const openAiDataMap = new Map();
openAiDataArray.forEach((data) => {
  if (data.id) {
    openAiDataMap.set(String(data.id), data);
  }
});

// ========== PROCESAR TODOS LOS ITEMS ==========
const validItems = [];

for (const item of $("Filter cars by price").all()) {
  const car = item.json;

  const sellerId = car.marketplace_listing_seller.id;

  if (!sellerId) {
    console.log(`Item sin seller_id, descartando: ${car.id}`);
    continue;
  }

  const openAiData = openAiDataMap.get(String(car.id));

  if (!openAiData) {
    console.log(`Item sin datos de OpenAI (posiblemente excluido): ${car.id}`);
    continue;
  }

  const tags = [];

  item.json.carprice = car.listing_price?.amount ?? 0;

  const priceAmount = Number(car.listing_price?.amount ?? 0);

  if (priceAmount > 2000) {
    allPrices.push(priceAmount);
  }

  const desc = String(car.redacted_description?.text ?? "").toLowerCase();
  const title = String(car.marketplace_listing_title ?? "").toLowerCase();

  const patioRegex =
    /\b(cr[eé]dito|financiamiento|financiaci[oó]n|cuotas?|entrada|recibimos|parte de pago|aceptamos|visitanos|visítenos|estamos ubicados)\b/i;
  if (patioRegex.test(desc)) {
    tags.push("PATIO");
  }

  const mecanicaRegex =
    /\b(reparar|reparaci[oó]n|dañad[oa]|chocado|siniestrado|fallando)\b/i;
  if (mecanicaRegex.test(desc)) {
    tags.push("MECANICA");
  }

  let finalLocation = "cliente";

  if (tags.includes("MECANICA")) {
    finalLocation = "taller";
  } else if (tags.includes("PATIO") || desc.includes("revendedor")) {
    finalLocation = "patio";
  }

  let finalMileage = null;
  let mileageSource = null;


  // ========== PARSEAR KILOMETRAJE ==========
function parseMileage(value) {
  if (value == null) return null;
  if (typeof value === 'number') return value;
  const match = String(value).replace(/\./g, '').match(/\d+/);
  return match ? parseInt(match[0], 10) : null;
}


  if (openAiData?.mileage) {
    finalMileage = parseMileage(openAiData.mileage);
    mileageSource = finalMileage ? "openai" : null;
} else if (car.vehicle_odometer_data?.value) {
    finalMileage = parseMileage(car.vehicle_odometer_data.value);
    mileageSource = finalMileage ? "facebook_odometer" : null;
}

  // ========== EXTRAER TODAS LAS IMÁGENES ==========
  const listingImageUrls = extractImageUrls(car);

  item.json.tags = tags;
  item.json.primaryTag = tags[0] ?? null;

  // ========== LIMPIAR CARACTERÍSTICAS CON LA FUNCIÓN ==========
  const cleanedCharacteristics = cleanCharacteristics(
    openAiData.specifications,
  );

  item.json.openai_extracted = {
    brand: openAiData.brand ?? null,
    model: openAiData.model ?? null,
    phone: openAiData.phone ?? null,
    mileage: openAiData.mileage ?? null,
    extras: openAiData.extras ?? null,
    characteristics: cleanedCharacteristics,
    motor: openAiData.motor ?? null,
    transmission: openAiData.transmission ?? null,
    trim: openAiData.trim ?? null
  };

  if (car.vehicle_odometer_data?.value) {
    item.json.mileage_from_fb_listing = car.vehicle_odometer_data.value;
  } else {
    item.json.mileage_from_fb_listing = null;
  }

  // ========== LIMPIAR ARRAYS ANTES DE GUARDAR ==========
  const cleanExtras =
    Array.isArray(openAiData.extras) && openAiData.extras.length > 0
      ? openAiData.extras
      : null;

  const cleanImageUrls =
    Array.isArray(listingImageUrls) && listingImageUrls.length > 0
      ? listingImageUrls
      : null;

  const cleanTags = Array.isArray(tags) && tags.length > 0 ? tags : null;

  item.json.mapped_data = {
    id: car.id,
    title: car.marketplace_listing_title,
    price: priceAmount,
    description: car.redacted_description?.text ?? "",
    location: finalLocation,
    seller_location: car.location_text?.text ?? null,
    condition: car.condition ?? null,
    year: extractYear(title, car.redacted_description?.text),
    url: car.listingUrl,
    publication_date: car.creation_time_formatted ?? null,
    image_url: car.primary_listing_photo.image.uri ?? null,
    listing_image_urls: cleanImageUrls,
    mileage: finalMileage,
    mileage_source: mileageSource,
    tags: cleanTags,
    is_sold: car.is_sold ?? false,
    is_pending: car.is_pending ?? false,
    seller_id: sellerId,
    seller_pic: car.marketplace_listing_seller.pic,
    seller_badges: car.commerce_badges_info?.source_summary ?? null,
    brand: openAiData.brand,
    model: openAiData.model,
    phone: openAiData.phone,
    extras: cleanExtras,
    characteristics: cleanedCharacteristics,
    motor: openAiData.motor,
    transmission: openAiData.transmission,
    trim: openAiData.trim ?? null,
    region: getDerivedRegion(car.location_text?.text ?? null)
  };

  validItems.push(item);
}

// ========== CALCULAR ESTADÍSTICAS ==========
const validPrices = allPrices.filter((p) => p > 0);
const totalPrices = validPrices.length;
const avgPrice =
  totalPrices > 0
    ? validPrices.reduce((sum, price) => sum + price, 0) / totalPrices
    : 0;
const minPrice = totalPrices > 0 ? Math.min(...validPrices) : 0;
const maxPrice = totalPrices > 0 ? Math.max(...validPrices) : 0;
const medianPrice =
  totalPrices > 0
    ? validPrices.sort((a, b) => a - b)[Math.floor(totalPrices / 2)]
    : 0;

for (const item of validItems) {
  item.json.price_statistics = {
    average_price: Math.round(avgPrice),
    median_price: medianPrice,
    min_price: minPrice,
    max_price: maxPrice,
    total_listings: totalPrices,
    total_items: validItems.length,
  };

  const itemPrice = Number(item.json.listing_price?.amount ?? 0);
  if (itemPrice > 0 && itemPrice < avgPrice * 0.7) {
    if (!item.json.tags) item.json.tags = [];
    item.json.tags.push("PRECIO_BAJO");
    if (!item.json.primaryTag) item.json.primaryTag = "PRECIO_BAJO";

    if (!item.json.mapped_data.tags) item.json.mapped_data.tags = [];
    item.json.mapped_data.tags.push("PRECIO_BAJO");
  } else if (itemPrice > avgPrice * 1.3) {
    if (!item.json.tags) item.json.tags = [];
    item.json.tags.push("PRECIO_ALTO");
    if (!item.json.primaryTag) item.json.primaryTag = "PRECIO_ALTO";

    if (!item.json.mapped_data.tags) item.json.mapped_data.tags = [];
    item.json.mapped_data.tags.push("PRECIO_ALTO");
  }

  // ✅ Limpiar tags finales
  if (
    Array.isArray(item.json.mapped_data.tags) &&
    item.json.mapped_data.tags.length === 0
  ) {
    item.json.mapped_data.tags = null;
  }
}

return validItems;

let encodeUriData = [];
let vehicleRequestsData = [];

try {
  encodeUriData = $input.all();
} catch (error) {
  console.log('Nodo "Scrap data by enconde uri" no ejecutado o sin datos');
}

try {
  vehicleRequestsData = $('Scrap data by vehicle requests').all();
} catch (error) {
  console.log('Nodo "Scrap data by vehicle requests" no ejecutado o sin datos');
}

const hasEncodeUriData = encodeUriData && encodeUriData.length > 0;
const hasVehicleRequestsData = vehicleRequestsData && vehicleRequestsData.length > 0;

console.log(`Datos en 'Scrap data by enconde uri': ${hasEncodeUriData ? encodeUriData.length : 0} items`);
console.log(`Datos en 'Scrap data by vehicle requests': ${hasVehicleRequestsData ? vehicleRequestsData.length : 0} items`);

if (hasEncodeUriData) {
  console.log('Retornando datos de: Scrap data by enconde uri');
  return encodeUriData;
} else if (hasVehicleRequestsData) {
  console.log('Retornando datos de: Scrap data by vehicle requests');
  return vehicleRequestsData;
} else {
  console.log('No hay datos en ninguno de los nodos');
  return [{ json: { total_items: 0 } }];
}

const out = [];

for (const item of $input.all()) {
  const url = item.json?.primary_listing_photo_url ?? [];
  const listingId = item.json.id

    if (!url) continue;

    const cleanUrl = String(url);
    const extMatch = cleanUrl.match(/\.(jpg|jpeg|png|webp|gif)(\?|$)/i);
    const ext = (extMatch?.[1] || 'jpg').toLowerCase();

    out.push({
      json: {
        listing_id: listingId,
        image_url: url,
        file_ext: ext,
        file_name: `${listingId}_photo.${ext}`,
        storage_path: `${listingId}/${listingId}_photo.${ext}`,
      },
    });
}

return out;

const items = $input.all();
const grouped = {};

for (const item of items) {
  // Supabase a veces devuelve el path en el response
  const storagePath = item.json.storage_path || item.json.Key || item.json.key;
  const listingId = item.json.listing_id;

  if (!listingId || !storagePath) {
    // Si faltan datos, skip
    continue;
  }

  const publicUrl = `https://enfqumrstqefbxtwsslq.supabase.co/storage/v1/object/public/vehicle_images/${storagePath}`;

  if (!grouped[listingId]) {
    grouped[listingId] = {
      listing_id: listingId,
      image_urls: [],
      vehicle_url: `https://www.facebook.com/marketplace/item/${listingId}`
    };
  }
  grouped[listingId].image_urls.push(publicUrl);
}

const result = Object.values(grouped);

if (result.length === 0) {
  throw new Error('No se pudo agrupar ninguna imagen. Verifica que listing_id y storage_path lleguen desde el nodo anterior.');
}

return result.map(g => ({ json: g }));

function safeLength(nodeName) {
  try {
    const items = $(nodeName).all();
    if (!items || !Array.isArray(items)) return 0;
    if (nodeName === 'Check if any data exists' && items.length === 1 && items[0].json?.total_items === 0) return 0;
    return items.length;
  } catch (e) { return 0; }
}

function countNewListingsSaved() {
  try {
    const items = $('Save Listings to DB').all();
    if (!items || !Array.isArray(items)) return 0;
    const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
    return items.filter(i => {
      const j = i.json;
      if (!j || !j.id) return false;
      if (typeof j.id !== 'string') return false;
      if (!UUID_REGEX.test(j.id)) return false;
      return !!(j.url || j.title);
    }).length;
  } catch (e) { return 0; }
}

function safeGetUrlsFromUpdateRow() {
  try {
    return $('Update a row').all().map(i => i.json?.mapped_data?.url || i.json?.url).filter(Boolean);
  } catch (e) { return []; }
}

function safeGetUrlsFromUpdateImages() {
  try {
    return $('Update images').all().map(i => i.json?.vehicle_url || i.json?.url).filter(Boolean);
  } catch (e) { return []; }
}

const totalScraped = safeLength('Check if any data exists');
const passedPriceFilter = safeLength('Filter cars by price');
const discardedByPrice = Math.max(0, totalScraped - passedPriceFilter);
const newListingsSaved = countNewListingsSaved();

const countUpdateRow = safeLength('Update a row');
const countUpdateImages = safeLength('Update images');
const urlsUpdateRow = safeGetUrlsFromUpdateRow();
const urlsUpdateImages = safeGetUrlsFromUpdateImages();
const uniqueUpdatedUrls = new Set([...urlsUpdateRow, ...urlsUpdateImages]);
const totalVehiculosActualizados = uniqueUpdatedUrls.size > 0 ? uniqueUpdatedUrls.size : (countUpdateRow + countUpdateImages);

const summary = {
  status: 'done',
  message: 'Scraping terminado exitosamente',
  resumen: {
    listings_nuevos_guardados: newListingsSaved,
    listings_descartados_por_precio: discardedByPrice,
    total_scrapeados: totalScraped,
    pasaron_filtro_precio: passedPriceFilter,
    total_vehiculos_actualizados: totalVehiculosActualizados
  }
};

return [{ json: summary }];

const BATCH_SIZE = 10;
const MAX_DESC_LEN = 500;
const inputItems = $('If').all();
const result = [];

// Construir set de URLs ya existentes en $input
const existingUrls = new Set(
  $input.all().map(it => it.json.url).filter(Boolean)
);

// Filtrar los que ya existen
const filteredItems = inputItems.filter(it => {
  const url = it.json.listingUrl ?? it.json.url ?? null;
  return !existingUrls.has(url);
});

for (let i = 0; i < filteredItems.length; i += BATCH_SIZE) {
  const slice = filteredItems.slice(i, i + BATCH_SIZE);
  const originals = slice.map((it) => ({ ...it.json }));

  const rows = slice.map((it) => {
    const row = it.json || {};
    const id = row.id ?? 'null';
    const title = String(row.marketplace_listing_title ?? row.title ?? '');
    const rawDesc = String(row.redacted_description?.text ?? row.description ?? '');
    let cleanDesc = rawDesc
      .replace(/\[hidden information\]/gi, '')
      .replace(/\b(no negociantes?|visítenos|visitanos|estamos ubicados.*)/gi, '')
      .replace(/\n+/g, '. ')
      .replace(/\s{2,}/g, ' ')
      .trim() || 'null';
    if (cleanDesc.length > MAX_DESC_LEN) cleanDesc = cleanDesc.slice(0, MAX_DESC_LEN) + '...';
    const desc = cleanDesc.includes(',') ? `"${cleanDesc}"` : cleanDesc;
    return `  ${id},${title},${desc}`;
  });

  result.push({
    json: {
      batch_index: result.length,
      _batch_originals: originals,
      batchText: `listings[${slice.length}]{id,title,description}:\n${rows.join('\n')}`
    }
  });
}

return result;

const output = [];

for (const item of $input.all()) {
  const row = item.json || {};
  const vehicles = row.message?.content?.vehicles;

  if (!Array.isArray(vehicles)) continue;

  for (const vehicle of vehicles) {
    output.push({
      json: {
        id: vehicle.id ?? null,
        brand: vehicle.brand ?? null,
        model: vehicle.model ?? null,
        mileage: vehicle.mileage ?? null,
        extras: Array.isArray(vehicle.extras) ? vehicle.extras : [],
        specifications: Array.isArray(vehicle.specifications) ? vehicle.specifications : [],
        motor: vehicle.motor ?? null,
        transmission: vehicle.transmission ?? null,
        excluded: Boolean(vehicle.excluded)
      }
    });
  }
}

return output;

