function normalize(value) {
  if (value == null || value === '') return '';
  return String(value)
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/([a-z])(\d)/g, '$1-$2')
    .replace(/(\d)([a-z])/g, '$1-$2')
    .replace(/[\s\(\)\/\\\.]+/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '');
}

const brandToModels = new Map();
for (const [brandKey, models] of Object.entries(ECUADOR_CAR_DATA)) {
  const nBrand = normalize(brandKey);
  brandToModels.set(nBrand, {
    canonicalBrand: brandKey,
    canonicalModels: models,
    normalizedModels: models.map(m => normalize(m))
  });
}

const recentSellersMap = new Map();
for (const sellerItem of $('Get sellers already con db').all()) {
  const json = sellerItem.json;
  if (json.fb_seller_id) {
    recentSellersMap.set(String(json.fb_seller_id), json.id);
  }
}

// Dedup: URLs que ya existen en scraper_vehicles
const existingUrls = new Set();
try {
  for (const dbItem of $('Get vehicles on db').all()) {
    const url = dbItem.json?.url;
    if (url) existingUrls.add(url.trim());
  }
} catch (e) { /* nodo no ejecutado */ }
console.log(`URLs ya existentes en DB: ${existingUrls.size}`);

const matchedItems = [];
let skippedDuplicates = 0;

const BRAND_ALIASES = {
  // Mercedes
  'mercedes': 'mercedes-benz',
  'benz': 'mercedes-benz',
  'mercedes-benz': 'mercedes-benz',
  'mercedes benz': 'mercedes-benz',
  // Citroën
  'citroen': 'citroen',
  // GWM
  'gwm': 'gwm-great-wall-motors',
  'great-wall': 'gwm-great-wall-motors',
  'great wall': 'gwm-great-wall-motors',
  'haval': 'gwm-great-wall-motors',
  // GAC
  'gac': 'gac-motor',
  // Land Rover
  'land-rover': 'land-rover',
  'landrover': 'land-rover',
  // SsangYong
  'ssangyong': 'ssangyong',
  'sang-yong': 'ssangyong',
};

// Aliases de modelos: variante normalizada → normalizada del catálogo
const MODEL_ALIASES = {
  // Chevrolet D-MAX
  'dmax': 'd-max',
  'd-max-high-power': 'd-max-high-power',
  'dmax-high-power': 'd-max-high-power',
  // Isuzu D-MAX
  'dmax': 'd-max',
  // Mazda BT-50
  'bt50': 'bt-50',
  'bt-50': 'bt-50',
  // Nissan X-Trail
  'xtrail': 'x-trail',
  'x-trail': 'x-trail',
  // Honda CR-V / HR-V
  'crv': 'cr-v',
  'hrv': 'hr-v',
  // Toyota RAV4
  'rav-4': 'rav-4',
  'rav4': 'rav-4',
  // Ford F-150
  'f150': 'f-150',
  'f-150': 'f-150',
  // Volkswagen ID.4
  'id4': 'id-4',
  'id-4': 'id-4',
  // Mazda MX-5
  'mx5': 'mx-5',
  // Toyota C-HR
  'chr': 'c-hr',
  'c-hr': 'c-hr',
};

for (const item of $('Map & tag listings').all()) {
  const mappedData = item.json.mapped_data;
  if (!mappedData?.seller_id) continue;

  const vehicleUrl = (mappedData.url || '').trim();
  if (vehicleUrl && existingUrls.has(vehicleUrl)) {
    skippedDuplicates++;
    continue;
  }

  const fbSellerId = String(mappedData.seller_id);
  if (!recentSellersMap.has(fbSellerId)) continue;

  const dbId = recentSellersMap.get(fbSellerId);

  const rawNBrand = normalize(mappedData.brand);
