const rawNModel = normalize(mappedData.model);
const nModel = MODEL_ALIASES[rawNModel] ?? rawNModel;

const entry = brandToModels.get(nBrand);
if (!entry) continue;

const modelIndex = entry.normalizedModels.findIndex(nm =>
  nModel === nm || nModel.includes(nm) || nm.includes(nModel)
);
if (modelIndex === -1) continue;

const canonicalBrand = entry.canonicalBrand;
const canonicalModel = entry.canonicalModels[modelIndex];

  matchedItems.push({
    json: {
      ...item.json,
      mapped_data: {
        ...mappedData,
        listing_id: dbId,
        brand: canonicalBrand,
        model: canonicalModel
      }
    }
  });
}

return matchedItems;

const idsToFilter = new Set();

for (const trueSeller of $('All true sellers').all()) {
  for (const listing of $('Map & tag listings').all()) {
    if (trueSeller.json.fb_seller_id === listing.json.mapped_data?.seller_id) {
      idsToFilter.add(String(listing.json.mapped_data.id));
    }
  }
}

const trueSellersFiltered = [];

for (const seller of $('All sellers').all()) {
  if (idsToFilter.has(String(seller.json.fb_seller_id ?? ''))) continue;

  // Buscar el listing correspondiente por id
  const listing = $('Map & tag listings').all().find(
    l => String(l.json.mapped_data?.id ?? '') === String(seller.json.fb_seller_id ?? '')
  );

  if (!listing) continue;

  trueSellersFiltered.push({
    ...listing,
    json: {
      ...listing.json,
      seller_db_id: seller.json.id ?? null,
      seller_pic: seller.json.pic ?? null
    }
  });
}

return trueSellersFiltered;

const existingIds = new Set(
  $('Get many rows').all().map(s => String(s.json.fb_seller_id ?? ''))
);

const seenIds = new Set();
const toCreate = [];

for (const item of $('Sellers Data').all()) {
  const fbSellerId = String(item.json.fb_seller_id ?? '');
  if (!fbSellerId) continue;
  if (existingIds.has(fbSellerId)) continue; // ya existe en DB
  if (seenIds.has(fbSellerId)) continue;     // duplicado en este batch

  seenIds.add(fbSellerId);
  toCreate.push({ ...item });
}

return toCreate;

